CREATE TABLE inventory (paid NUMERIC, shippingtype NUMERIC, reported NUMERIC, invoiced NUMERIC, idtransaction integer PRIMARY KEY, idbook numeric, type numeric, client text, ordernr numeric, unitnr numeric, unitprice numeric, shipping numberic, postage numeric, wholesaler numeric, transactiondate date, transactioninfo text, comment text);
CREATE TABLE costs (idcost INTEGER PRIMARY KEY, date TEXT, paid NUMERIC, type TEXT, sum NUMERIC, description TEXT, bookid NUMERIC);
CREATE TABLE books (saleprice NUMERIC, language NUMERIC, extrainfo BLOB, coverfile TEXT, weight NUMERIC, onlineshopwindow NUMERIC, onlineshop NUMERIC, distribution NUMERIC, category2 NUMERIC, category1 NUMERIC, link_googlebooks TEXT, reported NUMERIC, authorprice NUMERIC, royaltyreseller NUMERIC, royaltywebshop NUMERIC, commentcontract TEXT, quarter NUMERIC, vat NUMERIC, printingcost NUMERIC, contracted NUMERIC, printrun NUMERIC, contracttype NUMERIC, status_webpage NUMERIC, datepubd NUMERIC, datepubm NUMERIC, datepuby NUMERIC, idbook integer PRIMARY KEY, author varchar(160), title varchar(255), isbn varchar(50), publisher numeric, publishing text, pubyear varchar(50), format tinyint(4), pages smallint(6), series varchar(255), price int(6), sponsor tinyint(1), addedinfo varchar(255), link_website varchar(150), link_webshop varchar(150), link_bookline varchar(150), link_libri varchar(150), link_lira varchar(150), link_telekiteka varchar(150), link_alexandra varchar(150), imagename text, extraname text, status tinyint(1), status_contract tinyint(1), status_copyediting tinyint(1), status_dtp tinyint(1), status_cover tinyint(1), status_printing tinyint(1), status_billing tinyint(1), date_submission text, date_publication text, author_address text, author_email text, abstractshort text, blurb text, comment text, date_created datetime, date_modified datetime, overdue int);
